patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 0632f3cfc6dd..6ea7c96cfc5b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3307,6 +3307,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       Value *Arg = II->getArgOperand(0);
       Value *Vect;

+
       if (Value *NewOp =
               simplifyReductionOperand(Arg, /*CanReorderLanes=*/true)) {
         replaceUse(II->getOperandUse(0), NewOp);
@@ -3452,6 +3453,22 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
     }
     break;
   }
+  case Intrinsic::ldexp: {
+    Value *X = II->getArgOperand(0);
+    Value *Arg = II->getArgOperand(1);
+    Value *Cond;
+    Type *Ty = II->getType();
+
+    if (Ty->isFloatingPointTy() && match(Arg, m_ZExt(m_Value(Cond))) &&
+        Cond->getType()->isIntegerTy(1)) {
+      Constant *One = ConstantFP::get(Ty, 1.0);
+      Constant *Two = ConstantFP::get(Ty, 2.0);
+      Value *Scale = Builder.CreateSelect(Cond, Two, One);
+      Value *Res = Builder.CreateFMul(X, Scale);
+      return replaceInstUsesWith(CI, Res);
+    }
+    break;
+  }
   case Intrinsic::is_fpclass: {
     if (Instruction *I = foldIntrinsicIsFPClass(*II))
       return I;
@@ -3508,6 +3525,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

+
 // Fence instruction simplification
 Instruction *InstCombinerImpl::visitFenceInst(FenceInst &FI) {
   auto *NFI = dyn_cast<FenceInst>(FI.getNextNonDebugInstruction());
